#!/bin/sh
apk add --no-cache curl git
cd /mnt/server
if [ ! -f main.go ]; then
    echo "package main

import (
	\"fmt\"
	\"net/http\"
)

func main() {
	fmt.Println(\"Server started on :8080\")
	http.HandleFunc(\"/\", func(w http.ResponseWriter, r *http.Request) {
		fmt.Fprintf(w, \"Hello from Pterodactyl Golang!\")
	})
	http.ListenAndServe(\":8080\", nil)
}" > main.go
fi
